import { PrismaClient, ItemRarity, EquipSlot, ClassName } from './prisma.js';

const prisma = new PrismaClient();

/**
 * Seed catalog of equippable items. Every item gets its own unique
 * 64Ă—64 PNG under /sprites/items/<id>.png â€” generated by the
 * sprite-generation pipeline from per-item prompt seeds in
 * web/public/sprites/items/MANIFEST.json. The previous convention
 * (one icon per classĂ—slot) left the catalog with 19 shared
 * sprites; per-item sprites fix that.
 *
 * Stat curves per rarity (additive, applied to combat math):
 *   COMMON     :  1 stat Ă—  5-8
 *   UNCOMMON   :  2 stats Ă— 10-15
 *   RARE      :  2 stats Ă— 18-25
 *   EPIC      :  3 stats Ă— 30-45
 *   LEGENDARY  :  4 stats Ă— 55-75
 *   MYTHIC    :  5 stats Ă— 90-120
 *
 * Class restrictions lock items to a single class so the rarity drop
 * matches the user's progression (a Juggernaut can't wear phantom
 * leathers). Items without a classRestriction are universally
 * equippable.
 *
 * Item-id naming:
 *   tron_<class>_<slot>     â†’ Tron-era baseline (UNCOMMON, setId tron_set)
 *   shirt_<class>_basic     â†’ old common tier (plain shirts per class)
 *   armor_<class>_<tier>    â†’ old tiered body (warrior_1/2/3, rogue_1/2,
 *                             healer_1/2)
 *   head_<class>_<tier>     â†’ old tiered helm/hood (warrior_1/3, rogue_1/3,
 *                             healer_1/3)
 *   weapon_<class>_<tier>   â†’ old tiered weapons (warrior_1/2/4,
 *                             rogue_0/2, healer_1/3, burst_axe,
 *                             burst_dagger)
 *   shield_<class>_<tier>   â†’ old tiered shields
 *   <slot>_<adjective>      â†’ universal (no classRestriction)
 *
 * The sprite path for every item is `items/<id>.png` regardless of
 * which naming family the id comes from. This keeps the convention
 * flat â€” the GH Action reads MANIFEST.json, generates PNGs, drops
 * them into web/public/sprites/items/.
 */

type SeedItem = {
  id: string;
  name: string;
  description?: string;
  slot: EquipSlot;
  sprite: string;
  color: string;
  rarity: ItemRarity;
  stats: Record<string, number>;
  classRestriction?: ClassName | null;
  setId?: string | null;
};

// Helper to keep the seed table terse. sprite path is always
// items/<id>.png; the manifest pulls the prompt from the name.
const itemSprite = (id: string) => `items/${id}.png`;

