export async function seedItems() {
  for (const item of ITEMS) {
    await prisma.itemDef.upsert({
      where: { id: item.id },
      create: {
        id: item.id,
        name: item.name,
        description: item.description ?? null,
        slot: item.slot,
        sprite: item.sprite,
        color: item.color,
        rarity: item.rarity,
        stats: item.stats as any,
        classRestriction: item.classRestriction ?? null,
        setId: item.setId ?? null,
      },
      update: {
        name: item.name,
        description: item.description ?? null,
        slot: item.slot,
        sprite: item.sprite,
        color: item.color,
        rarity: item.rarity,
        stats: item.stats as any,
        classRestriction: item.classRestriction ?? null,
        setId: item.setId ?? null,
      },
    });
  }
  console.log(`[seed] upserted ${ITEMS.length} ItemDef rows`);
}

if (process.argv[1]?.endsWith('seedItems.ts') || process.argv[1]?.endsWith('seedItems.js')) {
  seedItems()
    .then(() => prisma.$disconnect())
    .catch((e) => {
      console.error(e);
      prisma.$disconnect();
      process.exit(1);
    });
}
